217	      if (!tpl) return c.json({ error: `unknown template: ${templateName}` }, 404);
218	      if (!tpl.is_active) return c.json({ error: `template inactive: ${templateName}` }, 400);
219	      const injectPrompt = body.inject_prompt === true;
220	      const tplArgs = isPlainObject(body.args) ? (body.args as Record<string, unknown>) : {};
221	      const cwdOverride = typeof body.cwd === "string" && body.cwd.trim() ? body.cwd.trim() : undefined;
222	
223	      if (injectPrompt) {
224	        // prompt 注入あり = delegation invoke 本体に委譲 (render + prompt file + env + run 記録 + --model)。
225	        const result = await deps.delegationService.invoke({
226	          call_name: tpl.call_name,
227	          args: tplArgs,
228	          cwd: cwdOverride,
229	          triggered_by: "web-spawn",
230	          spawn: true,
231	        });
232	        if (!result.ok) return c.json({ error: result.error, detail: result.details }, 400);
233	        return c.json({
234	          ok: true,
235	          pid: result.spawn_pid,
236	          command: result.spawn_command,
237	          run_id: result.run.id,
238	          injected_prompt: true,
239	        });
