230	  onSessionLost(lost: SessionRow): void {
231	    if (this.isCostBlocked()) return;
232	    const role = this.parseRole(lost);
233	    const lastTask = lost.current_task ?? "(不明)";
234	    const peers = this.deps.sessions.listSessions({ status: "active" });
235	    for (const peer of peers) {
236	      this.deps.tasks.enqueue({
237	        session_id: peer.id,
238	        kind: "session-departed",
239	        payload: {
240	          lost_session_id: lost.id,
241	          lost_role: role,
242	          lost_branch: lost.branch,
243	          lost_repo: lost.repo_path,
244	          last_task: lastTask,
245	          instructions:
246	            "離脱通知. 残作業に介入が必要そうなら chitchat に一言流すか、 ユーザに伝える程度で十分.",
247	        },
248	      });
249	    }
250	  }
