295	  onSessionEnd(session: SessionRow, bullets: object): void {
296	    if (this.isChatMuted() || this.isCostBlocked()) return;
297	    const role = this.refreshRole(session);
298	    this.deps.tasks.enqueue({
299	      session_id: session.id,
300	      kind: "daily-report",
301	      payload: {
302	        role,
303	        bullets,
304	        instructions:
305	          "本日のセッション終了. ロールに沿った 1〜2 段落の感想文 (ハイライト / 引っかかり / 明日への一言) を書き、 " +
306	          `POST /v1/reports/${session.id}/append { "role": "${role}", "monologue": "<text>" } で追記.`,
307	      },
308	    });
309	  }
