546	function actionColor(action: string): string {
547	  switch (action) {
548	    case "fire":   return "px-1 rounded bg-accent/20 text-accent";
549	    case "add":    return "px-1 rounded bg-ok/20 text-ok";
550	    case "remove": return "px-1 rounded bg-warn/20 text-warn";
551	    case "skip":   return "px-1 rounded bg-subtle/20 text-subtle";
552	    case "error":  return "px-1 rounded bg-danger/20 text-danger";
553	    default:       return "px-1 rounded bg-muted text-subtle";
554	  }
555	}
