92	async function get<T>(path: string): Promise<T> {
93	  const r = await fetch(`${BASE}${path}`);
94	  if (!r.ok) throw new Error(`${r.status} ${path}`);
95	  return (await r.json()) as T;
96	}
97	
98	async function post<T>(path: string, body: unknown): Promise<T> {
99	  const r = await fetch(`${BASE}${path}`, {
100	    method: "POST",
101	    headers: { "content-type": "application/json" },
102	    body: JSON.stringify(body),
103	  });
104	  if (!r.ok) throw new Error(`${r.status} ${path}`);
105	  return (await r.json()) as T;
106	}
107	
108	async function put<T>(path: string, body: unknown): Promise<T> {
109	  const r = await fetch(`${BASE}${path}`, {
110	    method: "PUT",
111	    headers: { "content-type": "application/json" },
112	    body: JSON.stringify(body),
113	  });
114	  if (!r.ok) throw new Error(`${r.status} ${path}`);
115	  return (await r.json()) as T;
116	}
117	
118	async function patch<T>(path: string, body: unknown): Promise<T> {
119	  const r = await fetch(`${BASE}${path}`, {
120	    method: "PATCH",
121	    headers: { "content-type": "application/json" },
122	    body: JSON.stringify(body),
123	  });
124	  if (!r.ok) throw new Error(`${r.status} ${path}`);
125	  return (await r.json()) as T;
126	}
127	
128	async function del<T>(path: string): Promise<T> {
129	  const r = await fetch(`${BASE}${path}`, { method: "DELETE" });
130	  if (!r.ok) throw new Error(`${r.status} ${path}`);
131	  return (await r.json()) as T;
132	}
