478	    ),
479	  personasFeedbackRecent: (limit = 50) =>
480	    get<{ feedback: PersonaFeedback[] }>(`/v1/personas/feedback/recent?limit=${limit}`),
481	  statList: () =>
482	    get<{
483	      items: Array<{
484	        session_id: string;
485	        latest_ts: number;
486	        payload: Record<string, unknown>;
487	        session: SessionRow | null;
488	      }>;
