494	      history: Array<{ id: number; ts: number; payload: Record<string, unknown> }>;
495	    }>(`/v1/stat/${encodeURIComponent(id)}`),
496	  conflicts: (params: { repo: string; branch?: string; exclude_session?: string }) => {
497	    const q = new URLSearchParams({ repo: params.repo });
498	    if (params.branch) q.set("branch", params.branch);
499	    if (params.exclude_session) q.set("exclude_session", params.exclude_session);
500	    return get<{
501	      repo: string;
502	      branch: string | null;
503	      conflicts: SessionRow[];
504	      branches: Array<{ branch: string; count: number }>;
505	    }>(`/v1/monitor/conflicts?${q.toString()}`);
506	  },
507	};
508	
509	export function fmtTs(ts: number): string {
510	  const d = new Date(ts * 1000);
511	  return d.toLocaleString("ja-JP", { hour12: false });
512	}
513	
514	export function fmtDuration(sec: number): string {
515	  const h = Math.floor(sec / 3600);
516	  const m = Math.floor((sec % 3600) / 60);
517	  const s = sec % 60;
518	  return `${h ? `${h}h` : ""}${m}m${s}s`;
519	}
520	
521	export function statusBadge(status: SessionRow["status"]): string {
522	  switch (status) {
523	    case "active":    return "bg-ok/20 text-ok";
524	    case "lost":      return "bg-warn/20 text-warn";
525	    case "abandoned": return "bg-danger/20 text-danger";
526	    case "ended":     return "bg-subtle/20 text-subtle";
527	  }
528	}
