1	/**
2	 * /v1/spawn — orchestrator endpoint. Spawns a new lictor-wrapped Claude
3	 * Code / Codex session in a Windows Terminal tab or window.
4	 *
5	 * Auth: Bearer token from `<cwd>/.spawn.token` (`Authorization: Bearer ...`
6	 * or `X-Concordia-Token: ...`). `GET /v1/spawn/info` (no auth) returns the
7	 * absolute path of the token file so callers can locate it without knowing
8	 * Concordia's cwd in advance.
9	 *
10	 * Concurrency is bounded by Windows Terminal itself; Concordia keeps the
11	 * last 50 spawn records in memory for debugging via `GET /v1/spawn/recent`.
12	 */
13	
14	import { Hono } from "hono";
15	import { randomUUID } from "node:crypto";
16	import {
17	  buildWtArgs,
18	  isSpawnProvider,
19	  resolveSpawnCwd,
20	  spawnSession,
21	  SPAWN_PROVIDERS,
22	  type SpawnMode,
23	  type SpawnRequest,
24	} from "../control/spawner.js";
25	import {
26	  ensureSpawnToken,
27	  extractBearer,
28	  spawnTokenPath,
29	  tokenMatches,
30	} from "../control/token.js";
31	import { createChildLogger } from "../shared/logger.js";
32	
33	const log = createChildLogger("api/spawn");
34	
35	export interface SpawnApiDeps {
36	  /** cwd Concordia was started in — used for token storage. */
37	  cwd?: string;
38	  /**
39	   * Default working directory the spawn endpoint applies when the caller
40	   * omits `cwd` (e.g. CONCORDIA_SPAWN_DEFAULT_CWD=E:\Document\Ars). Empty
41	   * or non-existent path = no fallback (Concordia's own cwd is used).
42	   */
43	  defaultSpawnCwd?: string;
44	  /**
45	   * 日次トークン予算を超過している間 true を返す。 true の間は spawn を 429 で
46	   * 拒否する (Concordia 発の新規セッション起動を止める)。 未指定なら無効。
47	   */
48	  isCostBlocked?: () => boolean;
49	}
50	
51	export interface SpawnRecord {
52	  id: string;
53	  ts: string;
54	  request: SpawnRequest;
55	  command: string[];
56	  pid: number | null;
57	}
58	
59	const RECENT_CAP = 50;
60	
61	export function spawnRouter(deps: SpawnApiDeps = {}): Hono {
62	  const app = new Hono();
63	  const cwd = deps.cwd ?? process.cwd();
64	  const expectedToken = ensureSpawnToken(cwd);
65	  const records: SpawnRecord[] = [];
66	
67	  log.info({ tokenPath: spawnTokenPath(cwd) }, "spawn endpoint enabled");
68	
69	  // No-auth: where to find the token + the default cwd UI will pre-fill.
70	  // (We don't return the token VALUE — only the path so callers can find it.)
71	  app.get("/info", (c) => {
72	    return c.json({
73	      token_path: spawnTokenPath(cwd),
74	      platform_supported: process.platform === "win32",
75	      default_cwd: deps.defaultSpawnCwd ?? "",
76	    });
77	  });
78	
79	  app.use("*", async (c, next) => {
80	    // /info is the only no-auth route; it's matched above before this hits.
81	    const provided = extractBearer((name) => c.req.header(name) ?? undefined);
82	    if (!provided || !tokenMatches(expectedToken, provided)) {
83	      return c.json({ error: "missing or invalid token" }, 401, {
84	        "www-authenticate": 'Bearer realm="concordia-spawn"',
85	      });
86	    }
87	    await next();
88	  });
89	
90	  app.post("/", async (c) => {
91	    // 日次トークン予算を超過している間は新規セッション起動を拒否する。
92	    if (deps.isCostBlocked?.()) {
93	      return c.json(
94	        { error: "cost budget exceeded — daily token budget reached, spawn blocked" },
95	        429,
96	      );
97	    }
98	    let body: Record<string, unknown>;
99	    try {
100	      body = await c.req.json<Record<string, unknown>>();
101	    } catch {
102	      return c.json({ error: "invalid JSON" }, 400);
103	    }
104	    const provider = (body.provider as string) ?? "claude";
105	    if (!isSpawnProvider(provider)) {
106	      return c.json(
107	        { error: `unknown provider: ${provider} (valid: ${SPAWN_PROVIDERS.join(", ")})` },
108	        400,
109	      );
110	    }
111	    const mode: SpawnMode = body.mode === "window" ? "window" : "tab";
112	    const request: SpawnRequest = {
113	      provider,
114	      mode,
115	      args: Array.isArray(body.args)
116	        ? (body.args as unknown[]).filter((x): x is string => typeof x === "string")
117	        : undefined,
118	      cwd: resolveSpawnCwd(body.cwd, deps.defaultSpawnCwd),
119	      title: typeof body.title === "string" ? body.title : undefined,
120	      // env は外部入力からは受け取らない (CWE-78 RCE 対策)。 spawn child に渡る env は
121	      // Concordia 内部が設定する allowlist key のみ (spawner.sanitizeSpawnEnv)。
122	    };
123	
124	    const result = spawnSession(request);
125	    if (!result.ok) {
126	      return c.json({ error: result.error }, 400);
127	    }
128	    const record: SpawnRecord = {
129	      id: randomUUID(),
130	      ts: new Date().toISOString(),
131	      request,
132	      command: result.command,
133	      pid: result.pid,
134	    };
135	    records.push(record);
136	    if (records.length > RECENT_CAP) records.splice(0, records.length - RECENT_CAP);
137	    log.info({ id: record.id, provider, mode, pid: record.pid }, "spawn launched");
138	    return c.json({ ok: true, id: record.id, pid: record.pid, command: result.command });
139	  });
140	
141	  app.get("/recent", (c) => {
142	    return c.json({ spawns: records.slice() });
143	  });
144	
145	  // Dry-run for the same payload shape — useful for UI previews.
146	  app.post("/preview", async (c) => {
147	    let body: Record<string, unknown>;
148	    try {
149	      body = await c.req.json<Record<string, unknown>>();
150	    } catch {
151	      return c.json({ error: "invalid JSON" }, 400);
152	    }
153	    const provider = (body.provider as string) ?? "claude";
154	    if (!isSpawnProvider(provider)) {
155	      return c.json(
156	        { error: `unknown provider: ${provider} (valid: ${SPAWN_PROVIDERS.join(", ")})` },
157	        400,
158	      );
159	    }
160	    const mode: SpawnMode = body.mode === "window" ? "window" : "tab";
161	    const args = buildWtArgs({
162	      provider,
163	      mode,
164	      args: Array.isArray(body.args)
165	        ? (body.args as unknown[]).filter((x): x is string => typeof x === "string")
166	        : undefined,
167	      cwd: resolveSpawnCwd(body.cwd, deps.defaultSpawnCwd),
168	      title: typeof body.title === "string" ? body.title : undefined,
169	    });
170	    return c.json({ command: ["wt.exe", ...args] });
171	  });
172	
173	  return app;
174	}
