10	function ToggleRow(props: {
11	  label: string;
12	  hint: string;
13	  /** true = "禁止中" 側 (warn), false = "稼働中" 側 (ok), null = loading */
14	  value: boolean | null;
15	  onToggle: (next: boolean) => void;
16	  busy: boolean;
17	  onLabel: string;
18	  offLabel: string;
19	  onAction: string;
20	  offAction: string;
21	}) {
22	  const on = props.value === true;
23	  const stateLabel = props.value === null ? "..." : on ? props.onLabel : props.offLabel;
24	  const actionLabel = props.value === null ? "..." : on ? props.onAction : props.offAction;
25	  const stateClasses = props.value === null
26	    ? "bg-muted text-subtle border-border"
27	    : on ? "bg-warn/20 border-warn text-warn" : "bg-ok/20 border-ok text-ok";
28	  return (
29	    <div className="bg-muted/40 border border-border rounded p-3 space-y-2">
30	      <div>
31	        <div className="text-sm font-medium">{props.label}</div>
32	        <div className="text-xs text-subtle mt-0.5">{props.hint}</div>
33	      </div>
34	      <div className="flex items-center gap-2">
35	        <span className="text-xs text-subtle shrink-0">現在:</span>
36	        <span className={`shrink-0 px-2 py-0.5 rounded text-xs border ${stateClasses}`}>{stateLabel}</span>
37	        <button
38	          disabled={props.busy || props.value === null}
39	          onClick={() => props.onToggle(!on)}
40	          className="ml-auto shrink-0 px-2 py-1 rounded text-xs border bg-accent/15 border-accent text-accent disabled:opacity-40"
41	          title={`${stateLabel} → ${actionLabel}`}
42	        >
43	          {actionLabel}
44	        </button>
45	      </div>
46	    </div>
47	  );
48	}
