50	/** 1 行のテキスト設定 (現在値 + 入力 + apply)。 */
51	function TextSettingRow(props: {
52	  label: string;
53	  hint?: React.ReactNode;
54	  current: string | null;
55	  placeholder?: string;
56	  busy: boolean;
57	  onApply: (value: string) => void;
58	}) {
59	  const [draft, setDraft] = useState("");
60	  useEffect(() => { if (props.current !== null) setDraft(props.current); }, [props.current]);
