getProposalRateLimit(): number {
  const raw = this.getRaw(KEY_PROPOSAL_RATE_LIMIT);
  if (raw === null) return DEFAULT_PROPOSAL_RATE_LIMIT;
  const n = Number(raw);
  return Number.isFinite(n) && n >= 0 && n <= 1 ? n : DEFAULT_PROPOSAL_RATE_LIMIT;
}

