223	      if (injectPrompt) {
224	        // prompt 注入あり = delegation invoke 本体に委譲 (render + prompt file + env + run 記録 + --model)。
225	        const result = await deps.delegationService.invoke({
226	          call_name: tpl.call_name,
227	          args: tplArgs,
228	          cwd: cwdOverride,
229	          triggered_by: "web-spawn",
230	          spawn: true,
231	        });
232	        if (!result.ok) return c.json({ error: result.error, detail: result.details }, 400);
233	        return c.json({
234	          ok: true,
235	          pid: result.spawn_pid,
236	          command: result.spawn_command,
237	          run_id: result.run.id,
238	          injected_prompt: true,
239	        });
240	      }
241	
242	      // prompt 注入なし = provider + model だけ採用した素のセッション。
243	      // cwd: caller override → テンプレ default_cwd の `${var}` を args で展開 (auto-model の
244	      // ヒント用に resolveDelegationSpawn より先に解決)。展開後が空 / 未解決 (`${` 残存) なら
245	      // undefined にして spawnDefaultCwd に委ねる。
246	      let tplCwd: string | undefined = cwdOverride;
247	      if (!tplCwd && tpl.default_cwd) {
248	        const expanded = substituteVars(tpl.default_cwd, tplArgs).trim();
249	        tplCwd = (expanded && !expanded.includes("${")) ? expanded : undefined;
250	      }
251	      // local-LLM レーンで model="auto" なら Famulus 黒箱に選ばせる (delegation invoke と同じ。
252	      // 選択 Sonnet は Famulus 内部 = Concordia は LLM-free)。それ以外は素通し。
253	      let modelInput = tpl.model;
254	      if (tpl.target_provider === "gemma4-12" && (tpl.model ?? "").trim().toLowerCase() === "auto") {
255	        modelInput = await resolveLocalModel(tpl.model, { project: tplCwd ? basename(tplCwd) : undefined, repo: tplCwd ?? null });
256	      }
257	      // 論理 provider (gemma4-12 等) → 実 spawn に解決 (delegation invoke と同じ写像)。
258	      const spawn = resolveDelegationSpawn(tpl.target_provider, modelInput);
259	      const spawnCwd = resolveSpawnCwd(tplCwd, deps.config.spawnDefaultCwd);
260	      const result = spawnSession({
261	        provider: spawn.provider,
262	        mode,
263	        args: spawn.args.length > 0 ? spawn.args : undefined,
264	        cwd: spawnCwd,
265	        title: `tpl:${tpl.call_name}`,
266	        // gemma4-12 の LICTOR_LOCAL_MODEL 等、 spawn 解決由来の env を渡す。
267	        env: spawn.env,
268	      });
269	      if (!result.ok) return c.json({ error: result.error }, 400);
270	      // delegation_emoji を pending registry に登録。session.started 受信時に cwd で claim して metadata に焼く。
271	      recordPendingDelegationSpawn({ cwd: spawnCwd, emoji: tpl.emoji ?? null, callName: tpl.call_name });
272	      return c.json({ ok: true, pid: result.pid, command: result.command, injected_prompt: false });
273	    }
274	
275	    // ── 従来経路: provider 直接指定 ───────────────────────────
276	    const provider = (body.provider as string) ?? "claude";
277	    if (!isSpawnProvider(provider)) {
278	      return c.json(
279	        { error: `unknown provider: ${provider} (valid: ${SPAWN_PROVIDERS.join(", ")})` },
280	        400,
281	      );
282	    }
283	    const result = spawnSession({
284	      provider,
285	      mode,
286	      args: Array.isArray(body.args)
287	        ? (body.args as unknown[]).filter((x): x is string => typeof x === "string")
288	        : undefined,
289	      cwd: resolveSpawnCwd(body.cwd, deps.config.spawnDefaultCwd),
290	      title: typeof body.title === "string" ? body.title : undefined,
291	      // env は外部入力からは受け取らない (CWE-78 RCE 対策)。 spawn child に渡る env は
292	      // Concordia 内部が設定する allowlist key のみ (spawner.sanitizeSpawnEnv)。
293	    });
294	    if (!result.ok) return c.json({ error: result.error }, 400);
295	    return c.json({ ok: true, pid: result.pid, command: result.command });
296	  });
297	
298	  // 管理 API: spawn の既定値を UI に晒す.
299	  // body.cwd を省略したときに実際に使われる path と、 platform_supported を返す.
300	  app.get("/v1/admin/spawn-defaults", (c) => {
301	    return c.json({
302	      default_cwd: deps.config.spawnDefaultCwd,
303	      platform_supported: process.platform === "win32",
304	    });
305	  });
306	
307	  // 管理 API: 既存 lictor-wrapped セッションを kill.
308	  // 1. session row から metadata.lictor_pid を取得
309	  // 2. プラットフォーム別に process tree を kill (Win: taskkill /F /T, POSIX: SIGTERM)
310	  // 3. session を ended に遷移 + end event append (stopped_by: admin)
311	  // 4. session-end フロー (report 生成 / 独白を #報告 へ投稿 / persona release) を実行
312	  //    DELETE /v1/sessions/:id と同じ helper (control/end-session-flow.ts) を経由する.
313	  app.post("/v1/admin/stop-session/:id", async (c) => {
314	    const id = c.req.param("id");
315	    const session = deps.repo.findSession(id);
316	    if (!session) return c.json({ error: "not_found" }, 404);
317	    if (!session.metadata) {
318	      return c.json({ error: "session has no metadata — was it lictor-wrapped?" }, 400);
319	    }
320	    let meta: { lictor_pid?: number };
321	    try {
322	      meta = JSON.parse(session.metadata) as { lictor_pid?: number };
323	    } catch {
324	      return c.json({ error: "session.metadata is not JSON" }, 400);
325	    }
326	    if (typeof meta.lictor_pid !== "number") {
327	      return c.json({ error: "session.metadata.lictor_pid missing" }, 400);
328	    }
329	    const killResult = stopSessionByLictorPid(meta.lictor_pid);
330	    if (!killResult.ok) return c.json({ error: killResult.error }, 500);
331	    const now = Math.floor(Date.now() / 1000);
332	    deps.repo.setStatus(id, "ended", now, now);
333	    deps.repo.appendEvent({
334	      session_id: id,
335	      ts: now,
336	      kind: "end",
337	      payload: { stopped_by: "admin", duration_sec: now - session.started_at },
338	    });
339	    const ended = deps.repo.findSession(id)!;
340	    const flow = await runSessionEndFlow(
341	      {
342	        repo: deps.repo,
343	        chat: deps.chat,
344	        dispatcher: deps.dispatcher,
345	        personas: deps.personas,
346	        config: deps.config,
347	      },
348	      ended,
349	    );
350	    return c.json({
351	      ok: true,
352	      pid: meta.lictor_pid,
353	      report_generated: flow.report !== null,
354	      monologue_posted: flow.postedMessageId !== null,
355	    });
356	  });
357	
358	  // ── 管理 API: 3 つの runtime toggle ─────────────────────────────────
359	  // schema_meta 永続化 + AdminState 経由で dispatcher / rule engine / proposer
360	  // が次の tick から反映する. 再起動不要. Web UI (/rules ページ) からも操作可.
361	
362	  app.get("/v1/admin/chat-mute", (c) => {
363	    return c.json({ muted: deps.adminState.getChatMuted() });
364	  });
365	  app.put("/v1/admin/chat-mute", async (c) => {
366	    const body = await c.req.json().catch(() => null);
367	    if (!body || typeof body.muted !== "boolean") {
368	      return c.json({ error: "body.muted (boolean) required" }, 400);
369	    }
370	    deps.adminState.setChatMuted(body.muted);
371	    return c.json({ muted: deps.adminState.getChatMuted() });
372	  });
373	
374	  app.get("/v1/admin/rules-enabled", (c) => {
375	    return c.json({ enabled: deps.adminState.getRulesEnabled() });
376	  });
377	  app.put("/v1/admin/rules-enabled", async (c) => {
378	    const body = await c.req.json().catch(() => null);
379	    if (!body || typeof body.enabled !== "boolean") {
380	      return c.json({ error: "body.enabled (boolean) required" }, 400);
381	    }
382	    deps.adminState.setRulesEnabled(body.enabled);
383	    return c.json({ enabled: deps.adminState.getRulesEnabled() });
384	  });
385	
386	  app.get("/v1/admin/rule-proposer-interval", (c) => {
387	    return c.json({
388	      interval_sec: deps.adminState.getRuleProposerIntervalSec(),
389	      min_sec: ADMIN_PROPOSER_INTERVAL_MIN,
390	      max_sec: ADMIN_PROPOSER_INTERVAL_MAX,
391	    });
392	  });
393	  app.put("/v1/admin/rule-proposer-interval", async (c) => {
394	    const body = await c.req.json().catch(() => null);
395	    const n = Number(body?.interval_sec);
396	    if (!Number.isFinite(n)) {
397	      return c.json({ error: "body.interval_sec (number) required" }, 400);
398	    }
399	    try {
400	      deps.adminState.setRuleProposerIntervalSec(n);
401	    } catch (err) {
402	      return c.json({ error: (err as Error).message }, 400);
403	    }
404	    return c.json({ interval_sec: deps.adminState.getRuleProposerIntervalSec() });
405	  });
406	
407	  // ワークスペースルート / GitHub Organization (schema_meta 永続化、 設定 GUI から編集)。
408	  // 変更は次の Discord/Slack bot start (= restart) で実効値として反映される。
409	  app.get("/v1/admin/workspace-root", (c) => {
410	    return c.json({ workspace_root: deps.adminState.getWorkspaceRoot() });
411	  });
412	  app.put("/v1/admin/workspace-root", async (c) => {
413	    const body = await c.req.json().catch(() => null);
414	    if (!body || typeof body.workspace_root !== "string") {
415	      return c.json({ error: "body.workspace_root (string) required" }, 400);
416	    }
417	    deps.adminState.setWorkspaceRoot(body.workspace_root);
418	    return c.json({ workspace_root: deps.adminState.getWorkspaceRoot() });
419	  });
