430	    deps.adminState.setWorkspaceRoots(body.workspace_roots as string[]);
431	    return c.json({ workspace_roots: deps.adminState.getWorkspaceRoots() });
432	  });
433	
434	  // コスト予算 (日次トークン上限)。 0 = 無効。 当日消費 / block 判定も併せて返す。
435	  app.get("/v1/admin/cost-budget", (c) => {
