450	    const status = deps.costStatus?.() ?? null;
451	    return c.json({
452	      daily_token_budget: deps.adminState.getDailyTokenBudget(),
453	      today_tokens: status?.todayTokens ?? 0,
454	      blocked: status?.blocked ?? false,
455	    });
456	  });
