458	  app.get("/v1/admin/github-org", (c) => {
459	    return c.json({ github_org: deps.adminState.getGithubOrg() });
460	  });
461	  app.put("/v1/admin/github-org", async (c) => {
462	    const body = await c.req.json().catch(() => null);
463	    if (!body || typeof body.github_org !== "string") {
464	      return c.json({ error: "body.github_org (string) required" }, 400);
