483	  // 絵文字→アクション 写像: 既定 + ユーザ上書き。 上書きは schema_meta 永続化で即時反映。
484	  app.get("/v1/admin/reaction-mappings", (c) => {
485	    const defaults = defaultReactionEmojiMap();
486	    const overrides = deps.adminState.getReactionEmojiOverrides();
487	    // action_help: 各カスタムコマンド (ワークフロー) が何をするかのヘルプ (GUI 表示用)。
488	    return c.json({ defaults, overrides, actions: WORKFLOW_ACTIONS, action_help: WORKFLOW_ACTION_HELP });
489	  });
490	  app.put("/v1/admin/reaction-mappings", async (c) => {
491	    const body = await c.req.json().catch(() => null);
492	    const emoji = typeof body?.emoji === "string" ? body.emoji.trim() : "";
493	    const action = typeof body?.action === "string" ? body.action : "";
494	    if (!emoji) return c.json({ error: "body.emoji (string) required" }, 400);
495	    if (!isWorkflowAction(action)) {
496	      return c.json({ error: `body.action must be one of ${WORKFLOW_ACTIONS.join(", ")}` }, 400);
497	    }
498	    deps.adminState.setReactionEmojiOverride(emoji, action);
499	    return c.json({ overrides: deps.adminState.getReactionEmojiOverrides() });
500	  });
501	  app.delete("/v1/admin/reaction-mappings/:emoji", (c) => {
