// ── 提案レートリミット (per-session 窓内上限) ────────────────────────────
// dispatcher が session へ提案 (chitchat / review / chat-reply / peer-log-react)
// を出す直前に tryConsumeProposal で枠を消費し、 窓内で上限到達なら skip する。
// 設定はグローバル既定 (proposal_rate_limit) + session 個別上書き (overrides)、
// 窓カウンタ状態 (counters) も schema_meta に永続化する (再起動を跨いで維持)。

/** グローバル既定のレート設定。 未設定 / 壊れた値なら 60s / 5 件。 */
getProposalRateLimit(): ProposalRateLimit {
  return (
    parseRateLimit(this.getRaw(KEY_PROPOSAL_RATE_LIMIT)) ?? {
      window_sec: DEFAULT_PROPOSAL_WINDOW_SEC,
      max_count: DEFAULT_PROPOSAL_MAX_COUNT,
    }
  );
}

setProposalRateLimit(windowSec: number, maxCount: number): void {
  this.setRaw(KEY_PROPOSAL_RATE_LIMIT, JSON.stringify(normalizeRateLimit(windowSec, maxCount)));
}

/** session 個別上書きの辞書 (空なら {})。 */
getProposalRateLimitOverrides(): Record<string, ProposalRateLimit> {
  const raw = this.getRaw(KEY_PROPOSAL_RATE_LIMIT_OVERRIDES);
  if (!raw) return {};
  try {
    const parsed = JSON.parse(raw) as unknown;
    if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
      const out: Record<string, ProposalRateLimit> = {};
      for (const [k, v] of Object.entries(parsed as Record<string, unknown>)) {
        const rl = parseRateLimit(typeof v === "string" ? v : JSON.stringify(v));
        if (rl) out[k] = rl;
      }
      return out;
    }
  } catch {
    // 壊れた値は無視 (空辞書扱い)。
  }
  return {};
}

/** 1 session の上書きを upsert。 */
setProposalRateLimitOverride(sessionId: string, windowSec: number, maxCount: number): void {
  const id = sessionId.trim();
  if (!id) throw new Error("session_id required");
  const cur = this.getProposalRateLimitOverrides();
  cur[id] = normalizeRateLimit(windowSec, maxCount);
  this.setRaw(KEY_PROPOSAL_RATE_LIMIT_OVERRIDES, JSON.stringify(cur));
}

/** 1 session の上書きを削除 (グローバル既定に戻す)。 */
clearProposalRateLimitOverride(sessionId: string): void {
  const id = sessionId.trim();
  const cur = this.getProposalRateLimitOverrides();
  if (!Object.prototype.hasOwnProperty.call(cur, id)) return;
  delete cur[id];
  this.setRaw(KEY_PROPOSAL_RATE_LIMIT_OVERRIDES, JSON.stringify(cur));
}

/** session の実効レート設定 (上書き優先、 無ければグローバル既定)。 */
effectiveProposalRateLimit(sessionId: string): ProposalRateLimit {
  return this.getProposalRateLimitOverrides()[sessionId] ?? this.getProposalRateLimit();
}

/**
 * 提案 1 件分のレート枠を消費しようと試みる (固定窓方式)。
 *   - max_count <= 0 は無制限 (常に allowed)。
 *   - 窓が明けていれば (now - window_start >= window_sec) カウンタをリセットして再開。
 *   - 窓内で count >= max_count なら allowed=false を返し、 カウンタは進めない。
 * allowed=true のときだけカウンタを +1 して永続化する。
 */
tryConsumeProposal(sessionId: string, nowSec: number): ProposalRateDecision {
  const cfg = this.effectiveProposalRateLimit(sessionId);
  if (cfg.max_count <= 0) {
    return { allowed: true, count: 0, limit: cfg.max_count, window_sec: cfg.window_sec, retry_after_sec: 0 };
  }
  const counters = this.getProposalCounters();
  const prev = counters[sessionId];
  const windowActive = prev !== undefined && nowSec - prev.window_start_sec < cfg.window_sec;
  const cur: ProposalCounter = windowActive ? { ...prev } : { window_start_sec: nowSec, count: 0 };
  if (cur.count >= cfg.max_count) {
    const retry = Math.max(0, cur.window_start_sec + cfg.window_sec - nowSec);
    return { allowed: false, count: cur.count, limit: cfg.max_count, window_sec: cfg.window_sec, retry_after_sec: retry };
  }
  cur.count += 1;
  counters[sessionId] = cur;
  this.setProposalCounters(counters);
  return { allowed: true, count: cur.count, limit: cfg.max_count, window_sec: cfg.window_sec, retry_after_sec: 0 };
}

private getProposalCounters(): Record<string, ProposalCounter> {
  const raw = this.getRaw(KEY_PROPOSAL_RATE_LIMIT_COUNTERS);
  if (!raw) return {};
  try {
    const parsed = JSON.parse(raw) as unknown;
    if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
      return parsed as Record<string, ProposalCounter>;
    }
  } catch {
    // 壊れた値は無視 (空からやり直し)。
  }
  return {};
}

private setProposalCounters(counters: Record<string, ProposalCounter>): void {
  this.setRaw(KEY_PROPOSAL_RATE_LIMIT_COUNTERS, JSON.stringify(counters));
}

