export const ADMIN_PROPOSAL_WINDOW_MIN = PROPOSAL_WINDOW_MIN;
export const ADMIN_PROPOSAL_WINDOW_MAX = PROPOSAL_WINDOW_MAX;
export const ADMIN_PROPOSAL_MAX_COUNT_MAX = PROPOSAL_MAX_COUNT_MAX;

/** window_sec / max_count を検証 + clamp して正規化する (非有限は throw)。 */
function normalizeRateLimit(windowSec: number, maxCount: number): ProposalRateLimit {
  if (!Number.isFinite(windowSec) || !Number.isFinite(maxCount)) {
    throw new Error("proposal_rate_limit window_sec / max_count must be finite numbers");
  }
  return {
    window_sec: clamp(Math.floor(windowSec), PROPOSAL_WINDOW_MIN, PROPOSAL_WINDOW_MAX),
    max_count: clamp(Math.floor(maxCount), 0, PROPOSAL_MAX_COUNT_MAX),
  };
}

/** schema_meta の JSON 文字列を ProposalRateLimit に復元 (壊れ / 非有限は null)。 */
function parseRateLimit(raw: string | null): ProposalRateLimit | null {
  if (!raw) return null;
  try {
    const p = JSON.parse(raw) as unknown;
    if (p && typeof p === "object" && !Array.isArray(p)) {
      const w = Number((p as Record<string, unknown>).window_sec);
      const m = Number((p as Record<string, unknown>).max_count);
      if (Number.isFinite(w) && Number.isFinite(m)) {
        return {
          window_sec: clamp(Math.floor(w), PROPOSAL_WINDOW_MIN, PROPOSAL_WINDOW_MAX),
          max_count: clamp(Math.floor(m), 0, PROPOSAL_MAX_COUNT_MAX),
        };
      }
    }
  } catch {
    // 壊れた値は無視。
  }
  return null;
}

