   * 提案系 (chitchat / review / chat-reply / peer-log-react) のみここを通す。
   * ライフサイクル通知 (session-departed / daily-report) は対象外。
   */
  private enqueueProposal(task: {
    session_id: string;
    kind: import("./db/tasks-repo.js").PendingTaskKind;
    payload: object;
  }): boolean {
    if (!this.checkProposalRate(task.session_id)) {
      dispatcherLog.info(
        { session_id: task.session_id, kind: task.kind },
