    default: deps.adminState.getProposalRateLimit(),
    overrides: deps.adminState.getProposalRateLimitOverrides(),
    window_min_sec: ADMIN_PROPOSAL_WINDOW_MIN,
    window_max_sec: ADMIN_PROPOSAL_WINDOW_MAX,
    max_count_max: ADMIN_PROPOSAL_MAX_COUNT_MAX,
  });
});
app.put("/v1/admin/proposal-rate-limit", async (c) => {
  const body = await c.req.json().catch(() => null);
  const windowSec = Number(body?.window_sec);
  const maxCount = Number(body?.max_count);
  if (!Number.isFinite(windowSec) || !Number.isFinite(maxCount)) {
    return c.json({ error: "body.window_sec / body.max_count (numbers) required" }, 400);
  }
  const sessionId = typeof body?.session_id === "string" ? body.session_id.trim() : "";
  try {
    if (sessionId) {
      deps.adminState.setProposalRateLimitOverride(sessionId, windowSec, maxCount);
    } else {
      deps.adminState.setProposalRateLimit(windowSec, maxCount);
    }
  } catch (err) {
    return c.json({ error: (err as Error).message }, 400);
  }
  return c.json({
    default: deps.adminState.getProposalRateLimit(),
    overrides: deps.adminState.getProposalRateLimitOverrides(),
  });
});
app.delete("/v1/admin/proposal-rate-limit/:sessionId", (c) => {
  deps.adminState.clearProposalRateLimitOverride(decodeURIComponent(c.req.param("sessionId")));
  return c.json({
    default: deps.adminState.getProposalRateLimit(),
    overrides: deps.adminState.getProposalRateLimitOverrides(),
  });
});

