// ─── 提案レートリミット (per-session 窓内上限) ───────────────────────────

interface RateLimit { window_sec: number; max_count: number }
interface RateLimitState {
  default: RateLimit;
  overrides: Record<string, RateLimit>;
  window_min_sec: number;
  window_max_sec: number;
  max_count_max: number;
}

export function ProposalRateLimitSection() {
  const [data, setData] = useState<RateLimitState | null>(null);
  const [busy, setBusy] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  // グローバル既定の編集 draft。
  const [winDraft, setWinDraft] = useState("");
  const [maxDraft, setMaxDraft] = useState("");
  // 新規 / 更新する session 上書きの draft。
  const [ovSession, setOvSession] = useState("");
  const [ovWin, setOvWin] = useState("");
  const [ovMax, setOvMax] = useState("");

  useEffect(() => { void refresh(); }, []);

  async function refresh() {
    try {
      const s = (await fetch("/v1/admin/proposal-rate-limit").then((r) => r.json())) as RateLimitState;
      setData(s);
      setWinDraft(String(s.default.window_sec));
      setMaxDraft(String(s.default.max_count));
      setError(null);
    } catch (err) { setError((err as Error).message); }
  }

  async function saveDefault() {
    setBusy("default"); setError(null);
    try {
      await putJson("/v1/admin/proposal-rate-limit", {
        window_sec: Number(winDraft), max_count: Number(maxDraft),
      });
      await refresh();
    } catch (err) { setError((err as Error).message); } finally { setBusy(null); }
  }

  async function saveOverride() {
    const id = ovSession.trim();
    if (!id) return;
    setBusy("override"); setError(null);
    try {
      await putJson("/v1/admin/proposal-rate-limit", {
        session_id: id, window_sec: Number(ovWin), max_count: Number(ovMax),
      });
      setOvSession(""); setOvWin(""); setOvMax("");
      await refresh();
    } catch (err) { setError((err as Error).message); } finally { setBusy(null); }
  }

  async function removeOverride(sessionId: string) {
    setBusy(`rm:${sessionId}`); setError(null);
    try {
      const r = await fetch(`/v1/admin/proposal-rate-limit/${encodeURIComponent(sessionId)}`, { method: "DELETE" });
      if (!r.ok) throw new Error(`HTTP ${r.status}`);
      await refresh();
    } catch (err) { setError((err as Error).message); } finally { setBusy(null); }
  }

  const def = data?.default;
  const overrides = data ? Object.entries(data.overrides) : [];

  return (
    <section className="space-y-3">
      <div>
        <h2 className="font-semibold text-sm">提案レートリミット</h2>
        <p className="text-subtle text-xs mt-0.5">
          session ごとに「窓 (秒) 内で出せる提案 (chitchat / review / chat-reply / peer-react) の上限件数」を設ける。
          窓内で上限に達した提案は skip し、 窓が明けたらカウントをリセットして再開する。 即時反映 + 再起動後も維持。
          上限 0 = 無制限 (OFF)。
        </p>
      </div>

      <div className="bg-muted/40 border border-border rounded p-3 space-y-2">
        <div className="text-sm font-medium">グローバル既定</div>
        <div className="text-xs text-subtle">
          現在: {def ? `${def.window_sec} 秒 / ${def.max_count} 件` : "..."}
          {data ? ` (窓は [${data.window_min_sec}, ${data.window_max_sec}] sec)` : ""}
        </div>
        <div className="flex items-center gap-2 flex-wrap">
          <span className="text-xs text-subtle shrink-0">窓(秒):</span>
          <input
            type="number" min={data?.window_min_sec ?? 1} max={data?.window_max_sec ?? 86400}
            value={winDraft} onChange={(e) => setWinDraft(e.target.value)} disabled={busy === "default"}
            className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono w-24"
          />
          <span className="text-xs text-subtle shrink-0">上限(件):</span>
          <input
            type="number" min={0} max={data?.max_count_max ?? 10000}
            value={maxDraft} onChange={(e) => setMaxDraft(e.target.value)} disabled={busy === "default"}
            className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono w-24"
          />
          <button
            disabled={busy === "default" || (def != null && winDraft === String(def.window_sec) && maxDraft === String(def.max_count))}
            onClick={() => void saveDefault()}
            className="shrink-0 px-3 py-1 bg-accent/15 border border-accent text-accent rounded text-xs disabled:opacity-40"
          >apply</button>
        </div>
      </div>

      <div className="bg-muted/40 border border-border rounded p-3 space-y-3">
        <div>
          <div className="text-sm font-medium">session 個別上書き</div>
          <div className="text-xs text-subtle mt-0.5">特定 session だけ既定と違うレートにする。 session_id を指定して登録 / 更新。</div>
        </div>
        <div className="flex items-center gap-2 flex-wrap">
          <input
            type="text" value={ovSession} onChange={(e) => setOvSession(e.target.value)}
            placeholder="session_id" disabled={busy === "override"}
            className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono flex-1 min-w-[140px]"
          />
          <input
            type="number" min={data?.window_min_sec ?? 1} max={data?.window_max_sec ?? 86400}
            value={ovWin} onChange={(e) => setOvWin(e.target.value)} placeholder="窓(秒)" disabled={busy === "override"}
            className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono w-20"
          />
          <input
            type="number" min={0} max={data?.max_count_max ?? 10000}
            value={ovMax} onChange={(e) => setOvMax(e.target.value)} placeholder="上限" disabled={busy === "override"}
            className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono w-20"
          />
          <button
            disabled={busy === "override" || !ovSession.trim() || ovWin === "" || ovMax === ""}
            onClick={() => void saveOverride()}
            className="px-3 py-1 bg-accent/15 border border-accent text-accent rounded text-xs disabled:opacity-40"
          >追加 / 更新</button>
        </div>
        {overrides.length === 0 ? (
          <div className="text-xs text-subtle">(上書きなし — 全 session が既定を使用)</div>
        ) : (
          <ul className="space-y-1">
            {overrides.map(([sid, rl]) => (
              <li key={sid} className="flex items-center gap-2 text-sm bg-surface border border-border rounded px-2 py-1">
                <span className="font-mono text-xs truncate" title={sid}>{sid}</span>
                <span className="text-subtle">→</span>
                <span className="font-mono text-xs">{rl.window_sec}s / {rl.max_count}件</span>
                <button
                  disabled={busy === `rm:${sid}`}
                  onClick={() => void removeOverride(sid)}
                  className="ml-auto text-subtle hover:text-danger text-xs"
                >削除</button>
              </li>
            ))}
          </ul>
        )}
      </div>

      {error && <div className="text-danger text-xs">{error}</div>}
    </section>
  );
}

