it("proposal_rate_limit: 既定 60s/5 + set-get + clamp + 永続", () => {
  expect(env.state.getProposalRateLimit()).toEqual({ window_sec: 60, max_count: 5 });
  env.state.setProposalRateLimit(30, 3);
  expect(env.state.getProposalRateLimit()).toEqual({ window_sec: 30, max_count: 3 });
  // 別インスタンスでも読める (永続)。
  expect(new AdminState(env.db).getProposalRateLimit()).toEqual({ window_sec: 30, max_count: 3 });
  // clamp: window は [1, 86400]、 max_count は [0, 10000]、 小数は floor。
  env.state.setProposalRateLimit(0, -5);
  expect(env.state.getProposalRateLimit()).toEqual({ window_sec: 1, max_count: 0 });
  env.state.setProposalRateLimit(999_999, 999_999);
  expect(env.state.getProposalRateLimit()).toEqual({ window_sec: 86400, max_count: 10000 });
  expect(() => env.state.setProposalRateLimit(NaN, 5)).toThrow();
});

it("proposal_rate_limit overrides: upsert / effective / clear / 永続", () => {
  env.state.setProposalRateLimit(60, 5);
  env.state.setProposalRateLimitOverride("sess-A", 10, 2);
  expect(env.state.getProposalRateLimitOverrides()).toEqual({ "sess-A": { window_sec: 10, max_count: 2 } });
  // 実効値: 上書きある session は上書き、 無い session は既定。
  expect(env.state.effectiveProposalRateLimit("sess-A")).toEqual({ window_sec: 10, max_count: 2 });
  expect(env.state.effectiveProposalRateLimit("sess-B")).toEqual({ window_sec: 60, max_count: 5 });
  // 永続。
  expect(new AdminState(env.db).effectiveProposalRateLimit("sess-A")).toEqual({ window_sec: 10, max_count: 2 });
  // clear で既定に戻る。
  env.state.clearProposalRateLimitOverride("sess-A");
  expect(env.state.getProposalRateLimitOverrides()).toEqual({});
  expect(env.state.effectiveProposalRateLimit("sess-A")).toEqual({ window_sec: 60, max_count: 5 });
});

it("tryConsumeProposal: 上限到達で skip → 窓明けで再開", () => {
  // 窓 10 秒 / 上限 2 件。
  env.state.setProposalRateLimit(10, 2);
  // t=100: 2 件までは allowed、 3 件目は skip。
  expect(env.state.tryConsumeProposal("s", 100).allowed).toBe(true); // count 1
  expect(env.state.tryConsumeProposal("s", 101).allowed).toBe(true); // count 2
  const denied = env.state.tryConsumeProposal("s", 102);
  expect(denied.allowed).toBe(false);
  expect(denied.count).toBe(2);
  expect(denied.limit).toBe(2);
  expect(denied.retry_after_sec).toBe(8); // 100 + 10 - 102
  // まだ窓内 (t=109) は引き続き skip。
  expect(env.state.tryConsumeProposal("s", 109).allowed).toBe(false);
  // 窓明け (t=110 = window_start+window_sec) でリセットして再開。
  expect(env.state.tryConsumeProposal("s", 110).allowed).toBe(true); // 新窓 count 1
  expect(env.state.tryConsumeProposal("s", 111).allowed).toBe(true); // count 2
  expect(env.state.tryConsumeProposal("s", 112).allowed).toBe(false);
});

it("tryConsumeProposal: max_count<=0 は無制限 / カウンタは永続", () => {
  env.state.setProposalRateLimit(60, 0);
  for (let i = 0; i < 50; i++) {
    expect(env.state.tryConsumeProposal("s", 100 + i).allowed).toBe(true);
  }
  // 上限ありに切り替えて、 カウンタが別インスタンスでも維持されることを確認。
  env.state.setProposalRateLimit(100, 1);
  expect(env.state.tryConsumeProposal("s2", 200).allowed).toBe(true); // count 1
  expect(new AdminState(env.db).tryConsumeProposal("s2", 201).allowed).toBe(false); // 永続カウンタで skip
});

it("tryConsumeProposal: session 個別上書きが既定より優先される", () => {
  env.state.setProposalRateLimit(60, 5);
  env.state.setProposalRateLimitOverride("tight", 60, 1);
  expect(env.state.tryConsumeProposal("tight", 300).allowed).toBe(true);
  expect(env.state.tryConsumeProposal("tight", 301).allowed).toBe(false); // 上書き上限 1 で skip
  // 既定 session は 5 件まで通る。
  for (let i = 0; i < 5; i++) expect(env.state.tryConsumeProposal("loose", 300 + i).allowed).toBe(true);
  expect(env.state.tryConsumeProposal("loose", 306).allowed).toBe(false);
});

