it("proposal-rate-limit: GET 既定 + PUT 既定更新 + session 上書き + DELETE", async () => {
  const get0 = await env.app.request("/v1/admin/proposal-rate-limit");
  expect(get0.status).toBe(200);
  const body0 = (await get0.json()) as { default: { window_sec: number; max_count: number }; overrides: Record<string, unknown> };
  expect(body0.default).toEqual({ window_sec: 60, max_count: 5 });
  expect(body0.overrides).toEqual({});

  // グローバル既定の更新 (clamp 込み: window 0 → 1)。
  const putDef = await env.app.request("/v1/admin/proposal-rate-limit", {
    method: "PUT",
    headers: { "content-type": "application/json" },
    body: JSON.stringify({ window_sec: 0, max_count: 3 }),
  });
  expect(putDef.status).toBe(200);
  expect((await putDef.json() as { default: unknown }).default).toEqual({ window_sec: 1, max_count: 3 });

  // session 個別上書き。
  const putOv = await env.app.request("/v1/admin/proposal-rate-limit", {
    method: "PUT",
    headers: { "content-type": "application/json" },
    body: JSON.stringify({ session_id: "sess-X", window_sec: 30, max_count: 2 }),
  });
  expect(putOv.status).toBe(200);
  expect((await putOv.json() as { overrides: Record<string, unknown> }).overrides).toEqual({
    "sess-X": { window_sec: 30, max_count: 2 },
  });

  // DELETE で上書き解除。
  const del = await env.app.request("/v1/admin/proposal-rate-limit/sess-X", { method: "DELETE" });
  expect(del.status).toBe(200);
  expect((await del.json() as { overrides: Record<string, unknown> }).overrides).toEqual({});
});

